using BenchmarkDotNet.Attributes;
using UglyToad.PdfPig;
using UglyToad.PdfPig.DocumentLayoutAnalysis.TextExtractor;
using Unchained.Pdf.Engine;
using Unchained.PerformanceTests.Infrastructure;

namespace Unchained.PerformanceTests.Benchmarks;

/// <summary>
///     Cross-library performance comparison: Unchained vs PdfPig (MIT, 0.1.14).
///     All libraries operate on identical PDF byte arrays generated by
///     <see cref="MinimalPdfFactory" /> — no third-party fixtures required.
/// </summary>
/// <remarks>
///     Run with:
///     dotnet run -c Release --framework net9.0 -- --filter "*Comparison*"
///     PdfPig (https://github.com/UglyToad/PdfPig, MIT) is the closest MIT alternative
///     to Unchained: pure-managed .NET, targets the same ISO 32000 parsing + text-extraction use cases.
/// </remarks>
[
    MemoryDiagnoser,
    GcServer,
    HideColumns("StdDev", "RatioSD", "Median"),
    BenchmarkCategory("Comparison")
]
// ReSharper disable once ClassCanBeSealed.Global
public class ComparisonBenchmark
{
    private byte[] _pdf10Pages = null!;
    private byte[] _pdf1Page = null!;
    private byte[] _pdfWithText = null!;
    private DocumentProcessor _processor = null!;

    [GlobalSetup]
    public void Setup()
    {
        _pdf1Page = MinimalPdfFactory.Build();
        _pdf10Pages = MinimalPdfFactory.Build(10);
        _pdfWithText = MinimalPdfFactory.BuildWithText(1, "Unchained benchmark: the quick brown fox jumps over the lazy dog.");
        _processor = new DocumentProcessor();
    }

    [GlobalCleanup]
    public void Cleanup() => _processor.Dispose();

    // ── Load 1-page PDF ───────────────────────────────────────────────────────

    [Benchmark(Baseline = true, Description = "Unchained — Load 1p")]
    public async Task<int> Unchained_Load_1Page()
    {
        await using var doc = await _processor.LoadAsync(new MemoryStream(_pdf1Page));
        return doc.PageCount;
    }

    [Benchmark(Description = "PdfPig — Load 1p")]
    public int PdfPig_Load_1Page()
    {
        using var doc = PdfDocument.Open(_pdf1Page);
        return doc.NumberOfPages;
    }

    // ── Load 10-page PDF ──────────────────────────────────────────────────────

    [Benchmark(Description = "Unchained — Load 10p")]
    public async Task<int> Unchained_Load_10Pages()
    {
        await using var doc = await _processor.LoadAsync(new MemoryStream(_pdf10Pages));
        return doc.PageCount;
    }

    [Benchmark(Description = "PdfPig — Load 10p")]
    public int PdfPig_Load_10Pages()
    {
        using var doc = PdfDocument.Open(_pdf10Pages);
        return doc.NumberOfPages;
    }

    // ── Load + iterate all page dimensions ────────────────────────────────────

    [Benchmark(Description = "Unchained — Page dims 10p")]
    public async Task<double> Unchained_PageDimensions_10Pages()
    {
        await using var doc = await _processor.LoadAsync(new MemoryStream(_pdf10Pages));
        var total = 0.0;
        for (var i = 1; i <= doc.PageCount; i++)
            total += doc.Pages[i].Width + doc.Pages[i].Height;
        return total;
    }

    [Benchmark(Description = "PdfPig — Page dims 10p")]
    public double PdfPig_PageDimensions_10Pages()
    {
        using var doc = PdfDocument.Open(_pdf10Pages);
        var total = 0.0;
        for (var i = 1; i <= doc.NumberOfPages; i++)
        {
            var page = doc.GetPage(i);
            total += page.Width + page.Height;
        }

        return total;
    }

    // ── Text extraction ───────────────────────────────────────────────────────

    [Benchmark(Description = "Unchained — ExtractText 1p")]
    public async Task<string> Unchained_ExtractText_1Page()
    {
        await using var doc = await _processor.LoadAsync(new MemoryStream(_pdfWithText));
        return doc.Pages[1].ExtractText();
    }

    [Benchmark(Description = "PdfPig — ExtractText 1p")]
    public string PdfPig_ExtractText_1Page()
    {
        using var doc = PdfDocument.Open(_pdfWithText);
        return ContentOrderTextExtractor.GetText(doc.GetPage(1));
    }

    // ── Save / serialize (Unchained only — PdfPig is read-only) ─────────────

    [Benchmark(Description = "Unchained — Save 1p")]
    public async Task<int> Unchained_Save_1Page()
    {
        await using var doc = await _processor.LoadAsync(new MemoryStream(_pdf1Page));
        using var ms = new MemoryStream();
        await _processor.SaveAsync(doc, ms);
        return (int)ms.Length;
    }
}
